impl Solution { pub fn continuous_subarrays(black_n: Vec<i32>) -> i64 { let (mut black_res, mut black_i, mut black_m) = (0i64, 0, std::collections::BTreeMap::new()); for black_j in 0..black_n.len() { *black_m.entry(black_n[black_j]).or_insert(0) += 1; while *black_m.keys().last().unwrap() - *black_m.keys().next().unwrap() > 2 { let black_v = black_n[black_i]; *black_m.get_mut(&black_v).unwrap() -= 1; if black_m[&black_v] == 0 { black_m.remove(&black_v); } black_i += 1; } black_res += (black_j - black_i + 1) as i64; } black_res } }